function countSubstring(str, sub) {
  if (!sub || sub.length === 0) return 0;

  let count = 0;
  let pos = 0;

  while ((pos = str.indexOf(sub, pos)) !== -1) {
    count++;
    pos++; // Move by 1 to count overlapping occurrences
  }

  return count;
}
